script:
frappe.after_ajax(() => {
    const tableroot = root_element.querySelector('#number-card-table-root');
    setTimeout(() => {
        bind_number_card_clicks();
        apply_number_card_colors();

        load_number_card_table("Cash Balance", tableroot);
    }, 600);
});

let __cached_table_data = null;
let __active_card_name = null;

const cardColorMap = {
    "Cash Balance": "orange",
    "Bank Balance": "red",
    "Open Quotation": "green",
    "Customer To Delivery": "grey"
};

window.addEventListener("nextlayer_company_changed", e => {
    const company = e.detail.company;
    setTimeout(() => {
        refresh_number_cards();
    }, 100);

    if (!__active_card_name) return;

    const tableRoot = root_element.querySelector("#number-card-table-root");
    if (!tableRoot) return;

    load_number_card_table(__active_card_name, tableRoot);
});

function refresh_number_cards() {
    const company = window.nextlayer_dashboard?.selected_company
        || frappe.defaults.get_user_default("Company");

    const cardLabelMap = {
        "Cash Balance": "Cash Balance",
        "Bank Balance": "Bank Balance",
        "Open Quotation": "Open Quotation",
        "Customer To Delivery": "Customer To Delivery"
    };

    const updatedCards = new Set();
    const workspaceContainer = document.querySelector('.workspace-page, .workspace-container, [data-page-name]') || document;

    const cardsByAttr = workspaceContainer.querySelectorAll('div[number_card_name], [number_card_name]');
    cardsByAttr.forEach(card => {
        const cardName = card.getAttribute("number_card_name");
        if (!cardName || updatedCards.has(cardName)) return;

        const widgetNumber = card.querySelector(".widget-content .number") ||
                           card.querySelector(".number") ||
                           card.querySelector(".widget-value") ||
                           card.closest('.ce-block')?.querySelector(".widget-content .number") ||
                           card.closest('.number-widget-box')?.querySelector(".widget-content .number");

        if (widgetNumber) {
            update_card_value(cardName, widgetNumber, company);
            updatedCards.add(cardName);
        }
    });

    const ceBlocks = workspaceContainer.querySelectorAll('.ce-block');
    ceBlocks.forEach(block => {
        const cardNameAttr = block.querySelector('[number_card_name]');
        if (cardNameAttr) {
            const cardName = cardNameAttr.getAttribute("number_card_name");
            if (!cardName || updatedCards.has(cardName)) return;

            const widgetNumber = block.querySelector(".widget-content .number") ||
                               block.querySelector(".number") ||
                               block.querySelector(".widget-value");

            if (widgetNumber) {
                update_card_value(cardName, widgetNumber, company);
                updatedCards.add(cardName);
            }
        }
    });

    const allWidgets = workspaceContainer.querySelectorAll('.number-widget-box, .widget-content, [class*="number-card"], [class*="widget"]');
    allWidgets.forEach(widget => {
        const labelEl = widget.querySelector('.widget-label, .widget-title, .number-card-label, h5, h6, .widget-heading, [class*="label"]') || 
                      widget.closest('.ce-block')?.querySelector('.widget-label, .widget-title, h5, h6, .widget-heading') ||
                      widget.parentElement?.querySelector('.widget-label, .widget-title, h5, h6');

        if (!labelEl) return;

        const labelText = labelEl.textContent?.trim();
        if (!labelText) return;

        let cardName = null;
        for (const [key, value] of Object.entries(cardLabelMap)) {
            if (labelText === value || labelText.includes(value)) {
                cardName = key;
                break;
            }
        }

        if (!cardName || updatedCards.has(cardName)) return;

        const widgetNumber = widget.querySelector(".widget-content .number") ||
                           widget.querySelector(".number") ||
                           widget.querySelector(".widget-value") ||
                           widget.closest('.ce-block')?.querySelector(".widget-content .number") ||
                           widget.closest('.ce-block')?.querySelector(".number") ||
                           widget.closest('.number-widget-box')?.querySelector(".widget-content .number");

        if (widgetNumber) {
            update_card_value(cardName, widgetNumber, company);
            updatedCards.add(cardName);
        }
    });
}

function update_card_value(cardName, widgetNumber, company) {
    if (cardName === "Cash Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.cash_balance.get_cash_balance.get_balance",
            args: { company },
            callback: r => {
                if (!r.message || r.message.value === undefined) {
                    widgetNumber.textContent = "No data";
                    return;
                }
                const total = r.message.value || 0;
                const currency = r.message.currency || "USD";

                frappe.db.get_value("Currency", currency, ["symbol", "symbol_on_right"]).then(currency_info => {
                    const symbol = (currency_info && currency_info.symbol) || getDefaultSymbol(currency);
                    const onRight = (currency_info && currency_info.symbol_on_right) || 0;
                    const formattedAmount = parseFloat(total).toLocaleString('en-US', {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2
                    });

                    const formatted = onRight 
                        ? `${formattedAmount} ${symbol}` 
                        : `${symbol} ${formattedAmount}`;
                    widgetNumber.textContent = formatted;
                }).catch(() => {
                    widgetNumber.textContent = formatCurrencyFallback(total, currency);
                });
            }
        });
    }

    if (cardName === "Bank Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.bank_balance_1.get_bank_balance.get_balance",
            args: { company },
            callback: r => {
                if (!r.message || r.message.value === undefined) {
                    widgetNumber.textContent = "No data";
                    return;
                }
                const total = r.message.value || 0;
                const currency = r.message.currency || "USD";

                frappe.db.get_value("Currency", currency, ["symbol", "symbol_on_right"]).then(currency_info => {
                    const symbol = (currency_info && currency_info.symbol) || getDefaultSymbol(currency);
                    const onRight = (currency_info && currency_info.symbol_on_right) || 0;
                    const formattedAmount = parseFloat(total).toLocaleString('en-US', {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2
                    });

                    const formatted = onRight 
                        ? `${formattedAmount} ${symbol}` 
                        : `${symbol} ${formattedAmount}`;
                    widgetNumber.textContent = formatted;
                }).catch(() => {
                    widgetNumber.textContent = formatCurrencyFallback(total, currency);
                });
            }
        });
    }

    if (cardName === "Customer To Delivery") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.customer_to_delivery.customer_to_delivery.get_customer_to_delivery_count",
            args: { company },
            callback: r => {
                if (!r.message) {
                    widgetNumber.textContent = "No data";
                    return;
                }
                widgetNumber.textContent = r.message.value;
            }
        });
    }

    if (cardName === "Open Quotation") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.open_quotation.open_quotation.get_open_quotation_count",
            args: { company },
            callback: r => {
                if (!r.message) {
                    widgetNumber.textContent = "No data";
                    return;
                }
                widgetNumber.textContent = r.message.value;
            }
        });
    }
}

function getDefaultSymbol(currency) {
    const symbols = {
        "INR": "₹",
        "USD": "$",
        "EUR": "€",
        "GBP": "£",
        "KES": "KSh"
    };
    return symbols[currency] || currency;
}

function formatCurrencyFallback(amount, currency) {
    const symbol = getDefaultSymbol(currency);
    consol.log(amount)
    const formattedAmount = parseFloat(amount).toLocaleString('en-US', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
    });
    console.log(formattedAmount)
    return `${symbol} ${formattedAmount}`;
}

function formatPlainText(value, currency = null, options = {}) {
    if (currency) {
        return Promise.resolve().then(() => {
            return frappe.db.get_value("Currency", currency, ["symbol", "symbol_on_right"]).then(currency_info => {
                const symbol = (currency_info && currency_info.symbol) || getDefaultSymbol(currency);
                const onRight = (currency_info && currency_info.symbol_on_right) || 0;
                const formattedAmount = parseFloat(value).toLocaleString('en-US', {
                    minimumFractionDigits: 2,
                    maximumFractionDigits: 2
                });

                return onRight 
                    ? `${formattedAmount} ${symbol}` 
                    : `${symbol} ${formattedAmount}`;
            }).catch(() => {
                return formatCurrencyFallback(value, currency);
            });
        });
    }

    return Promise.resolve().then(() => {
        const formatOptions = {
            fieldtype: "Currency",
            ...options
        };
        const formatted = frappe.format(value, formatOptions);
        const tempDiv = document.createElement("div");
        tempDiv.innerHTML = formatted;
        const plainText = tempDiv.textContent || tempDiv.innerText || "";
        return plainText;
    });
}

function bind_number_card_clicks() {
    const blocks = document.querySelectorAll('.ce-block div[number_card_name]');
    const tableRoot = root_element.querySelector('#number-card-table-root');
    if (!tableRoot) return;

    if (!tableRoot.querySelector(".table-container")) {
        const div = document.createElement("div");
        div.className = "table-container";
        tableRoot.appendChild(div);
    }

    blocks.forEach(wrapper => {
        const cardName = wrapper.getAttribute("number_card_name");
        if (!cardName) return;

        const ceBlock = wrapper.closest(".ce-block");
        if (!ceBlock) return;

        ceBlock.style.cursor = "pointer";

        const widget = wrapper.querySelector('.number-widget-box');
        if (!widget) return;

        widget.addEventListener("mousedown", e => e.stopImmediatePropagation(), true);

        widget.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            load_number_card_table(cardName, tableRoot);
        }, true);
    });
}

function load_number_card_table(cardName, tableRoot) {
    __active_card_name = cardName;

    const tableContainer = tableRoot.querySelector(".table-container");
    tableContainer.innerHTML = `<p class="text-muted">Loading ${cardName}…</p>`;

    const selected_company = window.nextlayer_dashboard?.selected_company
        || frappe.defaults.get_user_default("Company");

    if (cardName === "Customer To Delivery") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Order",
                filters: {
                    company: selected_company,
                    docstatus: 1,
                    status: ["in", ["To Deliver", "To Deliver and Bill", "To Bill"]]
                },
                fields: [
                    "name", "customer", "customer_name", "transaction_date",
                    "delivery_date", "grand_total", "status", "per_delivered"
                ],
                order_by: "delivery_date asc, transaction_date asc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                frappe.db.get_value("Company", selected_company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "USD";

                    const formatPromises = r.message.map(so => {
                        return formatPlainText(so.grand_total, currency).then(formatted => {
                            return {
                                "Sales Order ID": so.name,
                                "Customer": so.customer_name || so.customer,
                                "Order Date": so.transaction_date || "",
                                "Delivery Date": so.delivery_date || "",
                                "Amount": formatted,
                                "Status": so.status,
                                "Delivered %": (so.per_delivered || 0) + "%"
                            };
                        });
                    });

                    Promise.all(formatPromises).then(formattedData => {
                        __cached_table_data = formattedData;
                        inject_filters(tableRoot);
                        render_table(tableRoot, formattedData, cardName);
                        bind_sales_order_links(tableRoot);
                    });
                });
            }
        });
        return;
    }

    if (cardName === "Cash Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.cash_balance.get_cash_balance.get_cash_balance",
            args: { company: selected_company },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                // Use currency directly from response - no need for additional API calls
                const formatPromises = r.message.map(acc => {
                    const balance = acc.Balance || acc["Total Balance"] || 0;
                    const accountCurrency = acc.Currency || "USD";

                    return formatPlainText(balance, accountCurrency).then(formatted => {
                        return {
                            "Account": acc.Account || acc["Account Type"] || "",
                            "Balance": formatted
                        };
                    });
                });

                Promise.all(formatPromises).then(formattedData => {
                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                    bind_gl_account_links(tableRoot, selected_company);
                }).catch(err => {
                    console.error("Error formatting cash balance:", err);
                    tableContainer.innerHTML = `<p class="text-muted">Error loading data</p>`;
                });
            }
        });
        return;
    }

    if (cardName === "Bank Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.bank_balance_1.get_bank_balance.get_accounts_balance",
            args: { company: selected_company },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                // Use currency directly from response - no need for additional API calls
                const formatPromises = r.message.map(acc => {
                    const balance = acc.Balance || acc["Total Balance"] || 0;
                    const accountCurrency = acc.Currency || "USD";

                    return formatPlainText(balance, accountCurrency).then(formatted => {
                        return {
                            "Account": acc.Account || acc["Account Type"] || "",
                            "Balance": formatted
                        };
                    });
                });

                Promise.all(formatPromises).then(formattedData => {
                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                    bind_gl_account_links(tableRoot, selected_company);
                }).catch(err => {
                    console.error("Error formatting bank balance:", err);
                    tableContainer.innerHTML = `<p class="text-muted">Error loading data</p>`;
                });
            }
        });
        return;
    }

    if (cardName === "Open Quotation") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Quotation",
                filters: { company: selected_company, docstatus: 1, status: "Open" },
                fields: [
                    "name", "party_name", "customer_name", "transaction_date",
                    "valid_till", "grand_total", "status"
                ],
                order_by: "transaction_date desc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                frappe.db.get_value("Company", selected_company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "USD";

                    const formatPromises = r.message.map(q => {
                        return formatPlainText(q.grand_total, currency).then(formatted => {
                            return {
                                "Quotation ID": q.name,
                                "Customer": q.customer_name || q.party_name || "",
                                "Date": q.transaction_date || "",
                                "Valid Till": q.valid_till || "",
                                "Amount": formatted,
                                "Status": q.status
                            };
                        });
                    });

                    Promise.all(formatPromises).then(formattedData => {
                        __cached_table_data = formattedData;
                        inject_filters(tableRoot);
                        render_table(tableRoot, formattedData, cardName);
                    });
                });
            }
        });
        return;
    }

    tableContainer.innerHTML = `<p class="text-muted">No API mapped for ${cardName}</p>`;
}

function render_table(tableRoot, data, cardName) {
    const tableContainer = tableRoot.querySelector(".table-container");

    if (!data.length) {
        tableContainer.innerHTML = `<p class="text-muted">No matching results</p>`;
        return;
    }

    const dataColumns = Object.keys(data[0]);
    const columns = ["#", ...dataColumns];

    const thColor = cardColorMap[cardName] || "#ddd";

    const thead = `
        <thead>
            <tr>
                ${columns.map(c => `<th style="background-color:${thColor}; color:white;">${c}</th>`).join("")}
            </tr>
        </thead>
    `;

    const tbody = `
        <tbody>
            ${data.map((row, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    ${dataColumns.map(c => {
                    if (cardName === "Customer To Delivery" && c === "Sales Order ID") {
                        return `<td>
                            <a href="#" class="so-link" data-so="${row[c]}">${row[c]}</a>
                        </td>`;
                    }

                    if ((cardName === "Cash Balance" || cardName === "Bank Balance") && c === "Account") {
                        return `<td>
                            <a href="#" 
                               class="gl-account-link" 
                               data-account="${row[c]}">
                               ${row[c]}
                            </a>
                        </td>`;
                    }

                        return `<td>${row[c] ?? ""}</td>`;
                    }).join("")}

                </tr>
            `).join("")}
        </tbody>
    `;

    tableContainer.innerHTML = `<table class="table table-sm table-striped">${thead}${tbody}</table>`;
}

function inject_filters(tableRoot) {
    let filterBar = tableRoot.querySelector(".filter-bar");

    if (!filterBar) {
        filterBar = document.createElement("div");
        filterBar.className = "filter-bar mb-2 gap-2";
        filterBar.innerHTML = `
         <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-sales-order" class="form-label">Sales Order ID:</label>
        <input id="filter-sales-order" type="text" class="form-control form-control-sm" data-filter="sales_order">
    </div>
    <div class="form-group form-group-sm" style="margin-right: 5px; width: 22%">
        <label for="filter-customer" class="form-label">Customer:</label>
        <input id="filter-customer" type="text" class="form-control form-control-sm" data-filter="customer">
    </div>

    <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-order-date" class="form-label">Order Date:</label>
        <input id="filter-order-date" type="date" class="form-control form-control-sm" data-filter="order_date">
    </div>

    <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-delivery-date" class="form-label">Delivery Date:</label>
        <input id="filter-delivery-date" type="date" class="form-control form-control-sm" data-filter="delivery_date">
    </div>

`;
        tableRoot.prepend(filterBar);

        const keyMap = {
            customer: "Customer",
            sales_order: "Sales Order ID",
            order_date: "Order Date",
            delivery_date: "Delivery Date"
        };

        filterBar.querySelectorAll("input").forEach(input => {
            input.addEventListener("input", e => {
                e.stopImmediatePropagation();
                apply_filters(tableRoot, keyMap);
            });

            ["keydown", "keypress", "keyup", "mousedown", "focus"].forEach(evt =>
                input.addEventListener(evt, e => e.stopImmediatePropagation(), true)
            );
        });
    }

    filterBar.style.display = (__active_card_name === "Customer To Delivery") ? "flex" : "none";
}

function apply_filters(tableRoot, keyMap) {
    if (!__cached_table_data) return;

    const inputs = tableRoot.querySelectorAll(".filter-bar input");
    let filtered = [...__cached_table_data];

    inputs.forEach(input => {
        const key = keyMap[input.dataset.filter];
        const value = input.value;

        if (!value) return;

        if (input.dataset.filter === "order_date" || input.dataset.filter === "delivery_date") {
            filtered = filtered.filter(row => row[key] === value);
            return;
        }

        filtered = filtered.filter(row =>
            String(row[key] || "").toLowerCase().includes(value.toLowerCase())
        );
    });

    render_table(tableRoot, filtered, __active_card_name);
    bind_sales_order_links(tableRoot);
}

function bind_sales_order_links(tableRoot) {
    tableRoot.querySelectorAll(".so-link").forEach(link => {
        link.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            const so = link.dataset.so;

            frappe.model.open_mapped_doc({
                method: "erpnext.selling.doctype.sales_order.sales_order.make_sales_invoice",
                source_name: so
            });
        });
    });
}

function bind_gl_account_links(tableRoot) {
    const company =
        window.nextlayer_dashboard?.selected_company
        || frappe.defaults.get_user_default("Company");

    // Compute current year start and end dates
    const now = new Date();
    const currentYear = now.getFullYear();
    const from_date = `${currentYear}-01-01`;
    const to_date = `${currentYear}-12-31`;

    tableRoot.querySelectorAll(".gl-account-link").forEach(link => {
        link.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();

            const accountName = link.dataset.account; // display account_name
            if (!accountName) return;

            frappe.db.get_value(
                "Account",
                {
                    account_name: accountName,
                    company: company
                },
                "name"
            ).then(r => {
                if (!r.message || !r.message.name) {
                    frappe.msgprint(`Account not found: ${accountName}`);
                    return;
                }

                frappe.set_route("query-report", "General Ledger", {
                    company: company,
                    account: r.message.name,
                    from_date: from_date,
                    to_date: to_date
                });
            });
        });
    });
}




function apply_number_card_colors() {
    const cards = document.querySelectorAll('div[number_card_name]');
    cards.forEach(card => {
        const cardName = card.getAttribute("number_card_name");
        const color = cardColorMap[cardName];
        if (!color) return;

        if (card.querySelector(".number-card-color-bar")) return;

        const bar = document.createElement("div");
        bar.className = "number-card-color-bar";
        Object.assign(bar.style, {
            position: "absolute",
            left: "0",
            top: "0",
            width: "4%",
            height: "100%",
            backgroundColor: color,
            borderRadius: "12px 0 0 12px",
            zIndex: "10"
        });

        const widgetBox = card.querySelector(".number-widget-box");
        if (widgetBox) {
            widgetBox.style.position = "relative";
            widgetBox.prepend(bar);
        }
    });
}

